INSERT INTO `notifications` VALUES (1,'Hello World!','This is the first notification. We will post these whenever an upcoming major change is about to happen.',0,'https://www.librenms.org/notifications.rss','e9bf74634c19f09e03cdbd270563a258bc2ad1f4ab7d20de06ee60d2a4ebc3057c6779043b7475924cfb58ba505e6d0c752e4ec7b79c251c2a77d3426e34b12a','2015-09-27 03:00:00'),(2,'Important update being released','We are releasing an important update within the next 24 hours which provides some additional functionality when running daily.sh. Whilst we have done everything we can to test this across as many platforms as possible we thought it was worth letting you know.\\n\\nIf you notice issues with further updates after this one then please get in touch with us on either IRC or GitHub.',0,'https://www.librenms.org/notifications.rss','cbcf6be1a832606d23f4d9093c7fa7a12bd6930701868050de00a13a3fe57a9fa48d75dab78f1f20d25d19633468b7849562cc45430bb4cc9b4b8a8eda632a99','2015-12-04 02:00:00'),(3,'Poller changes','Earlier this month we released some updates which enable alpha versions of InfluxDB and MIB-based polling.\\nWe have some further updates planned for the near future which may affect polling, so if you are running a mission-critical LibreNMS instance, you may wish to consider disabling updates for the time being.\\nIf you notice any issues, please get in touch with us via IRC or GitHub.',0,'https://www.librenms.org/notifications.rss','e3c2426b447c0bf4c9f50d72dc6b14756bc86e59b3aefced08589d09763514269904ce713f9572723d2194263cc3728fd13ccef7f9b0045cbc1b8a3ac31dfb44','2016-01-10 02:00:00'),(4,'Redback SmartEdge OS change','On January 19th we will be merging a PR that will change devices currently detected as redback to be detected as seos.\\n\\nIf you have any alert rules or device groups that rely on this OS definition then you will need to update those rules to include seos.',0,'https://www.librenms.org/notifications.rss','22fc9b7f8d0d73c0e84489717d3d36126ec1f718ea05324c92ccdc9e33fe6b929f53514b7a84dbf97fd6cf9abc282a60cd40b400b7817105d54f7289923b1ae0','2016-01-17 02:00:00'),(5,'Imagemagick vulnerability','A vulnerability in ImageMagick has been released, please see https://imagetragick.com/ for more details.\\n\\nLibreNMS uses ImageMagick for pdf generation, we advise that you add the temporary fix in on the aforementioned website until patches for your distribution are available to update ImageMagick.',0,'https://www.librenms.org/notifications.rss','1de2979056fe29c86abf5e2eee546e249ee22a7e850ad43123e42c306b9e0d0c76c0e97505821ee171323c0fc904fb0b9e5faefdb9153e0edc290fa983c1f4a5','2016-05-04 03:00:00'),(6,'Component Alerting Change','On July 25th we will be merging a PR that changes the status codes that are used for the component feature. If you have alerting rules that reference component.status, %macros.component_alert or %macros.component_normal please disable these until after the PR has been merged. Updated documentation will be merged with the PR to: http://docs.librenms.org/Extensions/Component/#alert',0,'https://www.librenms.org/notifications.rss','036e0ae37d936c5dc155ed489b63f41be79e7abcbd0ccf4229a93da0a91848bb519e87604c1cc59a29b6e3a5ffb8beda8044286bc45f883956c6a66e7f46711f','2016-07-25 03:00:00'),(7,'NUT Ups Application monitoring update','On December 20th we will be merging a PR that fixes the polling of data for NUT Ups devices.\\n\\nUnfortunately this will require users to delete the existing data and allow it to be re-created.\\n\\nTo do this, you can delete rrd files app-ups-nut-ID.rrd. ID will be a unique ID. After removing this file then data collection will start again.',0,'https://www.librenms.org/notifications.rss','c5efb05c52f95df86dd3138dd90a1e287af142ff9dff1a5a52d8528d7c59cfea016fe16c969e9f952ac64d195100dfbe33d8386a385329207864514331eba1e4','2016-12-18 02:00:00'),(8,'Multimatic UPS detection changes','On December 21st we will be merging a PR that will change devices currently detected as multimatic to be detected as generex-ups.\\n\\nIf you have any alert rules or device groups that rely on this OS definition then you will need to update those rules to include generex-ups.',0,'https://www.librenms.org/notifications.rss','75b6edfe8a162dc5414e12420da3950cd9fecc452c9fb6e2e5578698de5b3200bcd08ff194224db6acaed91faaa0647d98b711d2132edd1185408b0791b0e9e2','2016-12-18 02:00:00'),(9,'Large schema update due to be released','Please see: https://community.librenms.org/t/large-schema-update-being-released/637 for further info.',0,'https://www.librenms.org/notifications.rss','1dd85dc0cc62c6c84da356897048c73aafeea5d533b32813a7d409b968235cc53e24a614d736739621ca779f5ac2b8ed90fc99dbf19151d0359c24099a11edac','2017-02-22 03:00:00'),(10,'Change to extremeware and xos discovery','On the 10th of March, we are changing the way that OS detection is done for Extremeware and XOS devices, this could lead to the OS changing so if you have alerting or groups that reference these os names then please be aware that you will need to update them.',0,'https://www.librenms.org/notifications.rss','09399fca57e340bf330aea8054c659c585c265ae6fe029a106fd088af7ed71bd971c18e330500600d39f018382425e521a1dfeb7487caf66691e99b574a689a8','2017-03-07 03:00:00'),(11,'Change to Ubiquiti Airfibre device type','On the 24th of March, we are changing device type for Ubiquiti AirFibre from network to wireless. See https://github.com/librenms/librenms/pull/6160 for PR.',0,'https://www.librenms.org/notifications.rss','5dd4cc9d5075610638d2e36ec290d886e84a0d2156f11c8dba9612ab29cc8f5493b92c4a7cb514bee3f1cba68c254c83b8c263bc09925da2e70acbccde6eaed3','2017-03-21 03:00:00'),(12,'Change to some DNOS discovery','On the 24th of March, we are changing the detection of some Dell DNOS devices to PowerConnect. This is to show the difference between v6 and v9 of the DNOS OS. See https://github.com/librenms/librenms/pull/6206 for PR.',0,'https://www.librenms.org/notifications.rss','e2e20560a5b18930ae62d730e4ec0442379e752f61d38afd97fd65e2518a61a2c02e11b3f6e79417bd7d14b120e05f8ab40b04802c21f500101a69295b3b9d7c','2017-03-23 03:00:00'),(13,'Change to Cisco UCM type from tele to collaboration','On the 10th of April 2017, we are changing the type Cisco UCM (cucm) devices from tele to collaboration. If you have any alert rules or groups based on this value please adjust them after the daily update on that date.',0,'https://www.librenms.org/notifications.rss','213870ee25a96df602ead3878a09f495d1b36f4acb61bf0809725be09829e9125c9accf045d0d9d56a2151cfeca0cced13985236b366adc8f7793a9372bf103a','2017-04-06 03:00:00'),(14,'Change to AXIS OS device type','On the 17th of April 2017, we are changing the device type of AXIS devices from network to appliance. If you have any alert rules or groups based on this value please adjust them after the daily update on that date.',0,'https://www.librenms.org/notifications.rss','bb14e914a5267a5f56618849eec2075b3f191820fd9349fb9961ffa5e4a53802ed35bbfdaaeab9306ab37f5393998ea70d6d5a96293c58705da8bbc4ce440102','2017-04-13 03:00:00'),(15,'Change to MGE, Eaton, and Powerware UPS os','On the 24th of April 2017, The following UPS devices os will change: mgeups(Galaxy)->apc-mgeups, mgeups->eaton-mgeups, powerware->eatonups.  If you have any alert rules or groups based on this value please adjust them after the daily update on that date.',0,'https://www.librenms.org/notifications.rss','e22f3fce1761431c47c542bae8bdab0fc498bcf20ae442c287d3c242564f0111df7b7a00256fd5c0d786aa79722e7af67de677c4e17f79a72c1fb4d3bbfa4d05','2017-04-20 03:00:00'),(16,'Change to IRC alerts','On the 8th of June 2017, we will change the way the ircbot displays alerts.  It will now start using the standard templating system.  You can customize the alert templates for irc using e.g. {if %transport == irc}.  Please be aware that overly long templates might lead to the bot being disconnected for excess flood.',0,'https://www.librenms.org/notifications.rss','8ba20c5c8682f633007e1c6b8ec8e2eb37dff4ea892d9157fbf8c559d852651f962450d68f54d69ac9487f9fd93681a17ff53f3359a053b69819c09c391013fe','2017-06-01 03:00:00'),(17,'Change Cisco Unified CM (cucm) detection to be ucos (Cisco Unified Communication OS)','On the 17th of June 2017, we are changing the os name of cucm to ucos to be inline with the Cisco name.',0,'https://www.librenms.org/notifications.rss','1c034e39b4f7af6c781a455ea95f388402e3bd49f4dfbc5b089ba67f771164624c254bb5dd4caf8ccf2a800fc829e226883051caca2acc7a643d7da0cd03a60d','2017-06-13 03:00:00'),(18,'Change Ubiquiti AirOS (airos) device type ','On the 10th of July 2017, we are changing the device type of Ubiquiti AirOS devices from network to wireless. If you have any alert rules or groups based on this value please adjust them after the daily update on that date.',0,'https://www.librenms.org/notifications.rss','3cfe2cf71c35aba3ca7cac808c4eb361e2d3f315c6117fd8be6f70b53266f80f8d4a7e803e9f0e53df934d50126486a1f0a1b846844c0a4de883c3fefee414da','2017-07-04 03:00:00'),(19,'PowerWalker devices will now use the EPPC MIB for sensors','On the 20th of July 2017, we are changing the PowerWalker OS to use the EPPC MIB for sensor data. This will bring with it some additional metrics but will also mean that historical graphs will no longer be available. If you require this data then we suggest you copy the rrd files out of the way for later use.',0,'https://www.librenms.org/notifications.rss','0d8efbc17cf996f89cbe4ecd4f3277fc29a999485efb23c4b851bb025505e5f8308eefa4ca65c69c5db7b5ee54af6e85eba9f0eb0c64cd09beba3c8de1a95873','2017-07-13 03:00:00'),(20,'EricssonLG iPECS devices OS name change','On the 25th of September 2017, we are changing the OS names for the ELG iPECS UCP from ipecs -> elg-ipecs-ucp and for the ELG iPECS ES from ericsson-es -> elg-ipecs-es. Please adjust any alert rules or device groups that use these OS names.',0,'https://www.librenms.org/notifications.rss','1124fe77dd571e0344bbf35a6922008307724e3287b34956701962ad7196a1f78f3bb8c0579d3de350539162e2e08478a77b636366946527d6d5c60408140136','2017-09-20 03:00:00'),(21,'Cisco SMB Linux OS changing to Cisco WAP','On the 27th of October 2017, we are changing the OS names for the Cisco SMB Linux devices from ciscosmblinux -> ciscowap. Please adjust any alert rules or device groups that use these OS names.',0,'https://www.librenms.org/notifications.rss','ead1dcb6ae862529c1254b757a4440ad40426c03fc7ec1e40be72810846e9d242808b097e07191e5d4f3354764b7cf2f0805123c34f98eb691699f7285be4ae1','2017-10-21 02:00:00'),(22,'API update will enforce user permissions, check your tokens','Please see https://community.librenms.org/t/api-update-will-enforce-user-permissions-check-your-api-tokens/2675 for more info',0,'https://www.librenms.org/notifications.rss','f19b66ce61254806ae4f33566b9c74bf893b53192165d7ee1d397ce2a7c24abadad9d3d809a780b1a69deceb9084211c6dc241a450dfd890b649cbf3fe3de35c','2017-11-26 02:00:00'),(23,'Cambium Refactor','On the 6th of December 2017, we are changing the OS names for all Cambium products to their respective category. (Ex: pmp, ptp650, ptp250, cmm) Please adjust any alert rules or device groups that use these OS names. This will bring with it some additional metrics but will also mean that some historical graphs for Cambium devices will no longer be available. ',0,'https://www.librenms.org/notifications.rss','f9c035e3148f4d513fa20f3574bb42807ea2a96c490b3be879d18c7a79c38001647d478e6ac380ab73c2d5d7a25767b465b2f05fad0875604f658bd4c9af84a0','2017-11-28 02:00:00'),(24,'cometsystem-p85xx OS changing to websensor','On the 11th of December 2017, we are changing the OS names for cometsystem-p85xx to websenor. Please adjust any alert rules or device groups that use these OS names. This will bring with it some additional metrics. ',0,'https://www.librenms.org/notifications.rss','c736d198ba7994c71cca96d24ef5b462a1060c4d2e4238bc812cddd217ec1417210c6ff65ec0d437bf0654d9ed118154e79e389d9d1d7d51d0f7de2a5691e44a','2017-12-06 02:00:00'),(25,'Processor Usage Refactor','February 5th we will merge a major processors rewrite.  Most will see no difference, some were fixed. The following will lose historical data: axos, calix, dsm, fiberhome, hbblmos.  If you have any issues, please come report in our Discord (https://t.libren.ms/discord). For more details, visit the pull request: https://git.io/vNyUK.',0,'https://www.librenms.org/notifications.rss','bf7f8e7a8fca1740d571ccb611d79cb2ad14288207d8c5c769a8b6ef55971bc31422dc4fc67455162b83cfa5148b81246552eda82736c1d83911bed66fed10df','2018-01-29 02:00:00'),(26,'raritan OS changing to raritan-pdu','On March 23rd we will merge a pull request which will rename the OS raritan to raritan-pdu.  Please adjust any alert rules or device groups that use these OS names.',0,'https://www.librenms.org/notifications.rss','2952984cb03903aba0c9bf743ae8e0e3694f76749b3b67509d826271a2c9b17e0c70a3094c1de5ea0fb487ee72e9b3eca517c73c39b7fc221c90720d19ade5ed','2018-03-19 03:00:00'),(27,'aerohive OS changing to hiveos-wireless','On March 23rd we will merge a pull request which will rename the OS aerohive to hiveos-wireless.  Please adjust any alert rules or device groups that use these OS names.',0,'https://www.librenms.org/notifications.rss','2689d4976b6e8f6c008917186b4604b255df676f50a129627908a506b2b1f6eb30a3a4b2791d9651531f4e7f364252c41475475d65ebb0146ab78980ea77c37a','2018-03-19 03:00:00'),(28,'avaya-ers and avaya-vsp OS\' changing to boss and voss.','On April 12th we will merge a pull request which will rename the OS\' avaya-ers and avaya-vsp OS\' to boss and voss respectively.  Please adjust any alert rules or device groups that use these OS names.',0,'https://www.librenms.org/notifications.rss','2e454d1215a9431ea6854ce3005430e96faffa1947a6a750eea5d8d58d5767103c58b01aa6f6332e610b6cdb8a0ae222158f5b048ec258d1202e5dd4d4cc4a0f','2018-04-07 03:00:00'),(29,'Manual intervention required for 1.40 update','When LibreNMS 1.40 is released on Wednesday May 30, there are some steps that need to be taken to restore your Web UI.  The poller should continue without interruption.  More details here: https://community.librenms.org/t/new-requirements-for-1-40/4057',0,'https://www.librenms.org/notifications.rss','8d11e8077be7245d83737cb02f69e5645c5dd52698b01ca2b8f5f6bb87512f0db3baf25a6b8c40a70a22c778e04f0a7eb26b1ab4b26498df5a86e3acb845d9c8','2018-05-22 03:00:00'),(30,'Cambium Cleanup','On Monday the 4th of July 2018, some cambium metrics(CRC errors, fecInErrors, fecOutErrors) are being migrated over to the Wireless Tab, the old data will be available for some time still but will be removed from the Graphs Tab in a future update. ',0,'https://www.librenms.org/notifications.rss','c8d91c8499085997f441442d3507cdb4a7428d96355ba335b06d14fc3835ecd2d91504cdf034518f426390ca7606ae5307f9951e49b9c50839018fb48d2faede','2018-05-31 03:00:00'),(31,'Calix OS reorganize','On Monday the 23rd of July 2018, The OS known as calix will be split into calix, exa, and occamos. Please update any device groups or alert rules which may reference this OS. See https://github.com/librenms/librenms/pull/8832 for more details.',0,'https://www.librenms.org/notifications.rss','6ca1639a70069146ddafa43e396ba0eeebd688e94b3542ed48827be55039449892e49d85a9698855ae44520db12848d8a7d81d62d03ef5aa170ac38096ad1f9d','2018-07-19 03:00:00'),(32,'CMTS OS reorganize','On Tuesday the 24th of July 2018, the OS known as cmts will be changed to arris-c4. Please update any device groups or alert rules which may reference this OS. See https://github.com/librenms/librenms/pull/8883 for more details.',0,'https://www.librenms.org/notifications.rss','613318ccacdfc95a0de35a984031a227194e3da12cd142271dc328d11cf322b417dd6a5c8be2e36ac7fd98e1a8cfb0c252946d328a9c79513e7271d22b0f8660','2018-07-26 03:00:00'),(33,'New authentication system','In ongoing efforts to improve LibreNMS, a new authentication system will be merged on Tuesday the 11th of September 2018. Existing configurations should continue to work.  For more details and to test https://github.com/librenms/librenms/pull/8702',0,'https://www.librenms.org/notifications.rss','d1c9cbb22a7845892f83d26db027616fa07845e4658933e6334e2823e20a974031321607434c48bb61f286311356ec2c9092b17eda0b1a2d9c0fd4d977b24372','2018-09-06 03:00:00'),(34,'Pre-checks for 1.44 - Please read','We haven\'t yet gone live with 1.44 yet, before we do we want to give you a heads up on things you should check before updating. We\'ve switched out our authentication system over to Laravel + some front end changes mean old setups could have issues. Please have a read of https://community.librenms.org/t/1-44-pre-announcement/5734',0,'https://www.librenms.org/notifications.rss','10af0f755b98cb5939f721f25c1554c5225389b5b594b8d7ee99739a36b864e07b3c607247bd61412a3b75691d3d71f7277892bb416d4ebdca613bff060a39cd','2018-10-03 03:00:00'),(35,'Deprecation of legacy alert transports + legacy templating engine','This is a notification to inform users that we are deprecating legacy transports and template support in the New Year 2019. Please see https://t.libren.ms/deprecation-alerting for further information.',0,'https://www.librenms.org/notifications.rss','468c7b26e1986d27cb2d96940a8987f9c1441c965f1b9df8c99a11acb3d5655606598a4a88f474aa68217c451a930262c43a61f044428834408e582f7c362be3','2018-10-18 03:00:00'),(36,'Reminder: Deprecation of legacy alert transports + legacy templating engine','This is a notification to inform users that we are deprecating legacy transports and template support in the New Year 2019. Please see https://t.libren.ms/deprecation-alerting for further information.',0,'https://www.librenms.org/notifications.rss','3ed41627946aeb33f63dbefad78272439d0f8ae214a01dfb28950b01b0d862f1a87840118a3dd82ab302478813149d92f0adeea25f222c2b06ecd71f29407519','2018-11-29 02:00:00'),(37,'Minimum PHP supported version changing to 7.1.3','Please note that we will be changing the minimum supported PHP version from 5.6.3 to 7.1.3 on the 1st of Feb 2019. You can read more about this change here: https://t.libren.ms/php7',0,'https://www.librenms.org/notifications.rss','c7bc4850dc3a3429a2b093ec20b8eea180061a47bcb181f6cee6d3cf0eb8750d203c4baaee4afa0d6cc6dfb525ef40c13e2fb334b0fb206c3aa797652623101a','2019-01-03 02:00:00'),(38,'Merging ethernetprobe2 into akcp','On January 15th, 2019 we will merge the ethernetprobe2 os into the akcp os.  This will also include improved sensor support.\\n\\nIf you have any alert rules or device groups that rely on this OS definition then you will need to update those rules to include akcp.',0,'https://www.librenms.org/notifications.rss','f7aa98b8b661b6eb367cf57779871730289837173bfd8cf8032b48347ba9ba7584ef983d7a7391eed13e207f46c4d2e066f3dd8bbe192211e5f38c786f64c689','2019-01-09 02:00:00'),(39,'Removing duplicate field (host) on eventlog table','The duplicate field host has been removed from the eventlog table. If you use this in your alert rules, you should update it to use the field device_id instead.',0,'https://www.librenms.org/notifications.rss','91a49a9181af57ee7d805c38358da526d581cac4e17dbfc5e0035aca8732cfe2bb1a105ea4f4b895b57676b73e61cf72616dcfe07c5438fc8bf2159e17b1eb8a','2019-01-11 02:00:00'),(40,'RouterOS \"Station Connected\" metric historical data','A naming typo was corrected for RouterOS \"Station connected\" metric. This will lead to a loss of historical data display for this particular value. This will happen on March 27, 2019. More info: https://t.libren.ms/amt4s',0,'https://www.librenms.org/notifications.rss','d97ff26a9e33ecaec827fcce7e6a9b6e4d2336dc6db64a253a0cc17ef98c00e3f4b7f5c4ff46bac11b20016f7daa0998ebe77bfb71851552cdd92dd44b7e1d79','2019-03-24 03:00:00'),(41,'LibreNMS Python Dispatcher Service V2 (breaking change)','Version two of the LibreNMS python dispatcher service will merged on May 21, 2019. This code now requires Redis 5.x and redis-py 3.x to operate (if using distributed polling). Failure to update Redis before v2 is released will cause your pollers to stop functioning.',0,'https://www.librenms.org/notifications.rss','049c8ea0ecf1f5454dc7e13af99d61e755bd5555e6e4c51299c30e9e24f621b559a32c14094f282e51dab3b7f880edcd25fa31a722da166dd7ba286143d31756','2019-05-09 03:00:00'),(42,'Update to services graphing','We are improving graphing support for services and as part of that change services graphs will be migrated to a new URL. Please remember to update it if you are linking to it directly. This will add the ability to directly select service graphs on the dashboard.',0,'https://www.librenms.org/notifications.rss','7a1fbef2d25598b3f0a3d4c92d0c0b534b30d9f9863ddd30f9d18160cae3ce04cf9f905718aca65411e9a71ec9736b3b9aa532ae71cd28c1602defee5caa8f88','2019-05-13 03:00:00'),(43,'Update of Api Transport (Breaking change only if you use current Api Transport)','The API Transport code will be updated the 4th of July in \'master\' branch, and at the end of July for release 1.54, to allow more flexible and secure definition of the POST/GET parameters. It is also possible to perform Basic Auth on the service. If you use Api Transport today, be aware that you must update the URL and parameters definition. If you don\'t update them, the Api Transport will not behave correctly and you may miss alerts via this transport. For more information, you can consult https://github.com/librenms/librenms/pull/10070 or https://community.librenms.org .',0,'https://www.librenms.org/notifications.rss','c3685aea067c27e14ab41b9b74759a62d89761b8eaf38c8b576f02f2c8094df4bdaf26cbc7827a882f4da4ed7f622f7045d7c97d3db9a530f928520b899ef174','2019-06-22 03:00:00'),(44,'Dell OS States reorganize','Due to a duplicate name in different Dell MIBs, devices recognised as \"dell\" os in LibreNMS will loose historical data. Change will occur on Sunday November 3rd. The sensors impacted : processorDeviceStatusStatus, memoryDeviceStatus, powerSupplyStatus, intrusionStatus, controllerState, arrayDiskState, virtualDiskState, batteryState. It is possible to manually rename RRD files if you need to keep them. More information here : https://github.com/librenms/librenms/pull/10539',0,'https://www.librenms.org/notifications.rss','43ef0f303c8efc734f4401733f15ad03ebacac1cc252faf17d4eb6e55f103b5fc1e21a86ddc7789db23d3ae46f971736eb449acd4740744922e80babf2f6e25e','2019-10-24 03:00:00'),(45,'Discovery Protocols behaviour change','On the 5th of March 2020, the behaviour of the discovery-protocols module which includes support for protocols such as xDP has changed, discovery protocols will now always be polled as soon as the module is enabled, but the discovered neighbours will only be added if the proper configuration setting is set, check the following PR for more details: https://github.com/librenms/librenms/pull/11189',0,'https://www.librenms.org/notifications.rss','16c8c0adcf2ebfae00a88a21aafe55bb97c2f7a1c4a2e50399e6e5eef18e2542cf557af0ffb08de4d277f4ddf11b9e94d35cd3dd6670221a74b56a27d0c5a224','2020-02-26 03:00:00'),(46,'PHP Sockets requirement','On March 10, 2020, LibreNMS will require the PHP sockets extension for the Graphite and OpenTSDB datastores.  Please make sure you have the extension installed and enabled.  You can log in to the LibreNMS CLI and run ./validate.php to verify.',0,'https://www.librenms.org/notifications.rss','3418c9dfdf141d78cc502680588b456128d50c9df0488b24cd682a7f49b16922f92b11abfa987d557f4c34b3fba843c82547a4dbec001f14d96f81657ee50a57','2020-03-01 03:00:00'),(47,'PHP 7.1 and Python 2 no longer supported','LibreNMS will soon require Python 3.5+ and PHP 7.2.5+. For more details check https://t.libren.ms/uo84c',0,'https://www.librenms.org/notifications.rss','f11928b48409052475770bdf87e8fbf539c6cc2c668b2ff4140b270c1086da3b829587210e6d2d4af9f9162096cc954218edc348ca59452e988732e1289475af','2020-05-10 03:00:00'),(48,'AOS OS discovery reorganize','Due to a duplicate name in different AOS MIBs, devices recognised as \"AOS\" os in LibreNMS will be detected now as aos, aos6 or aos7. Change will occur on Mon, 18 May 2020. Device_processor sensors of aos6 and aos7 will loose historical data (rrd file can be renamed if you want to keep data). More info at: https://github.com/librenms/librenms/pull/11500',0,'https://www.librenms.org/notifications.rss','543d50f9ddff2a3d2fa3f51f51d03692ba5877c870d32ed602f8ada9bd2097cdd4b5e9cd5a106b1b1454f1438c1fdfacabba0ad4e8796248ec4e82729f531f12','2020-05-13 03:00:00'),(49,'Alerting packet loss macro','The packet loss macros were broken recently. The quick fix is to have them resemble device up/down, which is similar to how they would function if fping_options.count=1. Hopefully, they can be fixed in the future, but be aware their functionality is degraded in the meantime.',0,'/opt/librenms/misc/notifications.rss','efbe20000a3161cd68f62c844432698e0d24f5b837e3dd948c5c7319c17c30599ff9f744e7c47f0142d0c188f73d55871575cf7480a049570d7a86dfaf1174dc','2024-04-06 03:00:00'),(50,'Removal of ciscoASA table','On the 12th of February 2025, we will be merging in pull request 16952 (https://github.com/librenms/librenms/pull/16952) which will remove the ciscoASA table. Please see https://community.librenms.org/t/remove-of-the-ciscoasa-table/26978 for further information.',0,'/opt/librenms/misc/notifications.rss','f24069e9e1bc53abd91b34848841a1f71f0ec9dbde33ae8ef90f3ff01f550ab2463247b6aa13e2a66d8c8aeeb249ecd5d44e9a7809ca178c53fdd6f78fcbdc5d','2025-01-19 03:00:00'),(51,'Storage table change','The storage table structure has changed and storage_deleted and storage_mib were removed. If you have alert rules that reference those fields, you can remove storage_deleted and change storage_mib to type.',0,'/opt/librenms/misc/notifications.rss','9b30ee16f158836d979a9948c59bbff7e7ae836d6bee450796dd3cc25301f8cd0ce908786b0b0d516c86626db43def7f8ad9613fa93fe7ee112dedd1c423a08a','2025-01-24 03:00:00'),(52,'cisco-access OS removal','We will be merging the cisco-access (C1200/C1300 based devices) OS into the ciscosb OS. This will be done on the 20th of March 2025. If you have any alert rules or groups that reference this old OS then please update them include ciscosb as soon as possible.',0,'/opt/librenms/misc/notifications.rss','ef77e07ce889ddc1d1b44c7b55272d52de4f52d2d071585193405020b1a98f26277b7e7cb4e247353ff881567b8f1927986b9dd653c3a33259f4a532ce8dc2d3','2025-03-02 03:00:00'),(53,'OS Definitions and discovery yaml file relocation','As part of the continued effort to improve LibreNMS, it\'s code base and associated files, we will be migrating the yaml files used for OS detection and support. Please see https://community.librenms.org/t/os-definitions-and-discovery-file-relocation/27646 for further information.',0,'/opt/librenms/misc/notifications.rss','6eecf84365411df744f258b4f372e7a57534b25c313060ce563eef73266aa1900fc3436909f13a56f0e4987f2cc1abeb3da31c06d572e29f6d4379977f38890f','2025-04-16 03:00:00');
/*!40000 ALTER TABLE `notifications` ENABLE KEYS */;
UNLOCK TABLES;

